Author one complete WGSL compute shader from the supplied contract.
Return only the complete WGSL source; no Markdown fence, diff, or explanation.
The shader must implement every binding, entry-point, dispatch, bounds, and arithmetic requirement exactly.
<task_id>writer-v1-mechanics-vector-add-f32</task_id>
<specification>
For every logical index, add the corresponding left and right f32 values and store the result at output_offset + index. Invocations at or beyond length must return without reading or writing storage.
</specification>
<interface_contract>
{
  "entryPoint": "main",
  "stage": "compute",
  "requiredOverrides": [
    {
      "name": "WORKGROUP_SIZE",
      "type": "u32",
      "default": 64
    }
  ],
  "bindings": [
    {
      "group": 0,
      "binding": 0,
      "name": "left_values",
      "kind": "read_only_storage",
      "wgslType": "array<f32>"
    },
    {
      "group": 0,
      "binding": 1,
      "name": "right_values",
      "kind": "read_only_storage",
      "wgslType": "array<f32>"
    },
    {
      "group": 0,
      "binding": 2,
      "name": "output_values",
      "kind": "read_write_storage",
      "wgslType": "array<f32>"
    },
    {
      "group": 0,
      "binding": 3,
      "name": "params",
      "kind": "uniform",
      "wgslType": "Params"
    }
  ],
  "uniformLayout": [
    {
      "name": "length",
      "type": "u32",
      "byteOffset": 0
    },
    {
      "name": "output_offset",
      "type": "u32",
      "byteOffset": 4
    },
    {
      "name": "first",
      "type": "f32",
      "byteOffset": 8
    },
    {
      "name": "second",
      "type": "f32",
      "byteOffset": 12
    }
  ],
  "dispatch": "ceil(length / WORKGROUP_SIZE) workgroups in x; y=1; z=1",
  "requiredBuiltin": "global_invocation_id",
  "boundsRule": "Return when global_invocation_id.x >= params.length.",
  "outputRule": "Write only output_values[params.output_offset + index]."
}
</interface_contract>

